head.script:
scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 6) , 0).getDate();  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)

scwin.vBasSdId = "/ui/ds/op/wrkrslts/stvwrkrslts/op_306_01_23b.xml";  // 본선작업실적조회

scwin.avgCnt1 = 0;
scwin.avgCnt2 = 0;
scwin.avgCnt3 = 0;
scwin.avgCnt4 = 0;
scwin.subTotalSum1 = 0;
scwin.subTotalSum2 = 0;
scwin.subTotalSum3 = 0;
scwin.subTotalSum4 = 0;
scwin.footerSum1 = 0;
scwin.footerSum2 = 0;
scwin.footerSum3 = 0;
scwin.footerSum4 = 0;


scwin.onpageload = function() {
	let memJson = $c.data.getMemInfo();
    console.log(memJson);
    scwin.loUpperLobranCd = memJson.loUpperLobranCd;
    scwin.loUpperLobranNm = memJson.loUpperLobranNm;

    const codeOptions = [
        { grpCd : "OP195", compID : "gr_TermEachCarryingVesselStevedoring:impExpClsCd"}
    ];
    $c.data.setCommonCode(codeOptions);

}; 

scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

        ica_qryStDt.setValue(scwin.vQryStDt);
	    ica_qryEndDt.setValue(scwin.vCurDate);
        ///임시
        //ica_qryStDt.setValue('20200101');
	    //ica_qryEndDt.setValue('20200201');
        //lc_lobran.setValue("6AA");
        ///임시
        $c.sbm.execute(sbm_lobran);
        lc_lobran.focus();

    }, {"delay":100});
};

scwin.sbm_lobran_submitdone = function (e) {
    if(e.responseJSON.GAUCE) {
        ds_lobran.setJSON(e.responseJSON.GAUCE);
        lc_lobran.setValue(scwin.loUpperLobranCd);
        ///임시
        //lc_lobran.setValue("6AA");
        ///임시
