        var cnt = ds_lobran.getRowCount();
        if(cnt == 0){
            $c.win.alert("점소 자료 조회에 실패하였습니다");
            return;
        } else {
            lc_lobran.setValue(scwin.loUpperLobranCd);
            ed_lodeptCd.setValue(scwin.loUpperLobranCd);
            ed_lodeptNm.setValue(scwin.loUpperLobranNm);

        }
*/        
    }

};

//-------------------------------------------------------------------------
// 기간별본선하역실적조회
//-------------------------------------------------------------------------
scwin.f_qeryList = async function (){
    var chk = await $c.gus.cfValidate([lc_lobran,ed_vsslCd,ica_qryStDt,ica_qryEndDt])
  	if (!chk) {	// 점소, 선박, 조회기간
  		return;
	}

	if (ica_qryStDt.text>ica_qryEndDt.text) {
		$c.win.alert(MSG_CM_ERR_039);
		ica_qryEndDt.focus();
		return;
	}

    dma_condition.setEmptyValue();
    //dma_condition.AddRow();

    dma_condition.set("lobranCd", lc_lobran.getValue());	// 점소
    dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());	// 본선관리번호
    dma_condition.set("vsslCd", ed_vsslCd.getValue());		    // 선박
    dma_condition.set("qryStDt", ica_qryStDt.getValue());	        // 조회기간 시작일
    dma_condition.set("qryEndDt", ica_qryEndDt.getValue());		// 조회기간 완료일
    dma_condition.set("lineCd", ed_lineCd.getValue());		// 조회기간 완료일
    dma_condition.set("commCd", ed_commCd.getValue());        // 조회기간 완료일
    dma_condition.set("pchsClntNo", ed_pchsClntNo.getValue());        // 조회기간 완료일

    //tr_TermEachCarryingVesselStevedoring.Post();
    $c.sbm.execute(sbm_TermEachCarryingVesselStevedoring);
} 

scwin.sbm_TermEachCarryingVesselStevedoring_submitdone = function (e) {
    var rowCnt = ds_TermEachCarryingVesselStevedoring.getRowCount();
