//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
	$c.gus.cfInitObjects(tbl_condition, null);
	lc_lobran.setValue(scwin.loUpperLobranCd);
    ica_qryStDt.setValue(scwin.vQryStDt);
	ica_qryEndDt.setValue(scwin.vCurDate);
	lc_lobran.focus();
}

