scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList = new Array();  // 공통POP-UP -> 요청화면
    var clntNo = ed_pchsClntNo.getValue();

    switch (disGubun) {
  	    case 1:
		//선박코드 팝업
			udc_vsslCd.cfCommonPopUp(scwin.callbackVsslCdInfo, pCode, pName, "F", null, null, null, null, null,null,null,null,null,null,"T");//부서
			//cfSetReturnValue(rtnList, ed_vsslCd, txt_vsslNm);
			break;

		case 2:
			//마스터 LINE 팝업
			udc_lineCd.cfCommonPopUp(scwin.callbackLineInfo	// XML상의 SELECT ID	
  									,pCode					// 화면에서의 ??? Code Element의	Value
  									,pName					// 화면에서의 ??? Name Element의	Value
  									,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
  									,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
  									,null					// Title순서	
  									,null					// 보여주는 각 컬럼들의 폭	
  									,null					// 컬럼중에서 숨기는	컬럼 지정	
  									,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
  									,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
  									,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
  									,null					// 윈도우 위치 Y좌표	
  									,null					// 윈도우 위치 X좌표
  									,null					// 중복체크여부	("F")
  									,'F'					// 전체검색허용여부	("F")
  									,"LINE,LINE코드,LINE명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
  									);
            break;
        case 3:
            //품명코드팝업
            udc_commCd.cfCommonPopUp(scwin.callbackCommInfo,pCode.trim(),pName,pClose,null,null,null,null,',,4,,'+clntNo,null,null,null,null,null,pAllSearch,'품명,품명코드,품명');

            //cfSetReturnValue(rtnList, ed_commCd, ed_commNm);  // 품명코드, 품명명
            break;

        case 6:
            // 매입거래처 팝업
            rtnList = udc_pchsClntNo.cfCommonPopUp(scwin.callbackClntList,pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);

            //cfSetReturnValue(rtnList, ed_pchsClntNo, ed_pchsClntNm);  // 매입거래처코드,매입거래처명

            break;

        default:
            break;
    }
}

