scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    /*
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;
    */
    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        if (inObj == ed_commCd) {
            scwin.f_openCommonPopUp(3, pVal, '', 'T', 'T');
        } else if(inObj == ed_pchsClntNo){
            scwin.f_openCommonPopUp(6, pVal, '', 'T', 'T');
        }else {
            scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        }
    // inObj가 코드명 필드일 경우 팝업

}

scwin.btn_cvsslMgntNo_onclick = function (e) {
    scwin.f_openPopUp();
};

scwin.callbackVsslCdInfo = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_vsslCd, ed_vsslNm);
}

scwin.callbackLineInfo = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_lineCd, ed_lineNm);
}

scwin.callbackCommInfo = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_commCd, ed_commNm);  // 품명코드, 품명명
}

scwin.callbackClntList = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_pchsClntNo, ed_pchsClntNm);  // 매입거래처코드,매입거래처명
}

scwin.udc_vsslCd_onblurCodeEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_vsslCd.getValue(), '', 'T', 'T');
};

scwin.udc_lineCd_onblurCodeEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_lineCd.getValue(), '', 'T', 'T');
};

scwin.udc_commCd_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_commCd, ed_commNm, 3);
};

scwin.udc_pchsClntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_pchsClntNo, ed_pchsClntNm, 6);
};

scwin.udc_vsslCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_vsslCd.getValue(), ed_vsslNm.getValue(), 'F', 'T');
};

scwin.udc_pchsClntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(6, ed_pchsClntNo.getValue(), ed_pchsClntNm.getValue(), 'F', 'F');
};

scwin.udc_pchsClntNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_pchsClntNm, ed_pchsClntNo, 6, false);
};

scwin.udc_lineCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_lineCd.getValue(), ed_lineNm.getValue(),'F','F');
};

scwin.udc_lineCd_onviewchangeNameEvent = function (info) {
    scwin.f_openCommonPopUp(2, ed_lineCd.getValue(), '', 'T', 'T');
};

scwin.udc_commCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(3, ed_commCd.getValue(), ed_commNm.getValue(), 'F', 'F');
};

scwin.udc_commCd_onviewchangeNameEvent = function (info) {
